  1→# ConfigMigrator.ps1
  2→# INI configuration file parser, validator, and converter
  3→# Supports: INI -> JSON and INI -> YAML conversion with schema validation
  4→#
  5→# Approach:
  6→# - ConvertFrom-Ini: Parses INI content into nested ordered dictionaries
  7→#   with automatic type coercion (strings -> int, float, bool, null)
  8→# - Test-IniSchema: Validates parsed config against a JSON schema defining
  9→#   required keys and expected types per section
 10→# - ConvertTo-JsonConfig: Serializes parsed config to formatted JSON
 11→# - ConvertTo-YamlConfig: Serializes parsed config to YAML (custom writer
 12→#   since PowerShell has no built-in YAML support)
 13→
 14→# =============================================================================
 15→# Helper: Coerce a raw string value to the appropriate .NET type
 16→# =============================================================================
 17→function Convert-IniValue {
 18→    [CmdletBinding()]
 19→    param(
 20→        [Parameter(Mandatory)]
 21→        [AllowEmptyString()]
 22→        [string]$RawValue
 23→    )
 24→
 25→    # Empty string stays as empty string
 26→    if ($RawValue -eq '') {
 27→        return ''
 28→    }
 29→
 30→    # Quoted strings: strip quotes, preserve as string (no further coercion)
 31→    if ($RawValue.Length -ge 2 -and $RawValue[0] -eq '"' -and $RawValue[-1] -eq '"') {
 32→        return $RawValue.Substring(1, $RawValue.Length - 2)
 33→    }
 34→
 35→    # Null-like values
 36→    if ($RawValue -eq 'null' -or $RawValue -eq 'none') {
 37→        return $null
 38→    }
 39→
 40→    # Boolean values (case-insensitive)
 41→    switch ($RawValue.ToLower()) {
 42→        'true'  { return $true }
 43→        'false' { return $false }
 44→        'yes'   { return $true }
 45→        'no'    { return $false }
 46→        'on'    { return $true }
 47→        'off'   { return $false }
 48→    }
 49→
 50→    # Integer values (including negative)
 51→    if ($RawValue -match '^-?\d+$') {
 52→        return [int64]$RawValue
 53→    }
 54→
 55→    # Float values (decimal or scientific notation)
 56→    if ($RawValue -match '^-?\d+\.\d+([eE][+-]?\d+)?$' -or $RawValue -match '^-?\d+[eE][+-]?\d+$') {
 57→        return [double]$RawValue
 58→    }
 59→
 60→    # Default: return as string
 61→    return $RawValue
 62→}
 63→
 64→# =============================================================================
 65→# ConvertFrom-Ini: Parse INI content or file into ordered dictionary
 66→# =============================================================================
 67→function ConvertFrom-Ini {
 68→    [CmdletBinding(DefaultParameterSetName = 'Content')]
 69→    param(
 70→        [Parameter(ParameterSetName = 'Content', Mandatory)]
 71→        [string]$Content,
 72→
 73→        [Parameter(ParameterSetName = 'Path', Mandatory)]
 74→        [string]$Path
 75→    )
 76→
 77→    # If a file path was given, read its content
 78→    if ($PSCmdlet.ParameterSetName -eq 'Path') {
 79→        if (-not (Test-Path -LiteralPath $Path)) {
 80→            throw "File does not exist: $Path"
 81→        }
 82→        $Content = Get-Content -LiteralPath $Path -Raw
 83→    }
 84→
 85→    # Split content into lines
 86→    $lines = $Content -split "`r?`n"
 87→
 88→    # Pre-process: join backslash-continued lines
 89→    $processedLines = [System.Collections.Generic.List[string]]::new()
 90→    $i = 0
 91→    while ($i -lt $lines.Count) {
 92→        $line = $lines[$i]
 93→        # If line ends with backslash, join with next line
 94→        while ($line -match '\\$' -and ($i + 1) -lt $lines.Count) {
 95→            # Remove trailing backslash and join with next line (trimmed)
 96→            $line = $line.TrimEnd('\').TrimEnd() + ' ' + $lines[$i + 1].Trim()
 97→            $i++
 98→        }
 99→        $processedLines.Add($line)
100→        $i++
101→    }
102→
103→    # Parse into ordered dictionary of sections
104→    $result = [ordered]@{}
105→    $currentSection = $null
106→
107→    foreach ($line in $processedLines) {
108→        $trimmed = $line.Trim()
109→
110→        # Skip empty lines
111→        if ($trimmed -eq '') { continue }
112→
113→        # Skip comment lines (semicolon or hash)
114→        if ($trimmed[0] -eq ';' -or $trimmed[0] -eq '#') { continue }
115→
116→        # Section header: [section_name]
117→        if ($trimmed -match '^\[(.+)\]$') {
118→            $currentSection = $Matches[1].Trim()
119→            if (-not $result.Contains($currentSection)) {
120→                $result[$currentSection] = [ordered]@{}
121→            }
122→            continue
123→        }
124→
125→        # Key-value pair: key = value
